from openai import OpenAI
import json, time

client = OpenAI(api_key="your-key", base_url="https://api.deepseek.com/v1")

class PlanExecuteAgent:
    """计划-执行智能体：先制定详细计划，再逐步执行并检查"""
    def __init__(self, max_retries: int = 2):
        self.max_retries = max_retries
        self.plan: list[dict] = []
        self.execution_log: list[dict] = []

    def plan_task(self, task: str) -> list[dict]:
        """将复杂任务分解为有序子任务"""
        prompt = f"""请将以下任务分解为 4-6 个有序子任务。输出 JSON 数组，每个元素包含:
- "id": 序号
- "description": 子任务描述
- "checkpoint": 验证条件（如何判断该步骤完成）
任务: {task}
只输出 JSON 数组，不要其他内容。"""
        resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], temperature=0.3, max_tokens=1000)
        self.plan = json.loads(resp.choices[0].message.content.strip().strip("```json").strip("```"))
        print(f"📋 已生成 {len(self.plan)} 步计划")
        return self.plan

    def execute_step(self, task: str, step: dict, context: str) -> dict:
        """执行单个子任务"""
        prompt = f"""原始任务: {task}
当前步骤: {step['description']}
验证条件: {step['checkpoint']}
已完成上下文: {context}
请完成当前步骤并输出结果。"""
        resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], max_tokens=600)
        return {"step_id": step["id"], "result": resp.choices[0].message.content, "passed": True}

    def check_step(self, step: dict, result: str) -> bool:
        """检查点验证"""
        prompt = f"""验证条件: {step['checkpoint']}
执行结果: {result}
该步骤是否满足验证条件？只回答"是"或"否"。"""
        resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], temperature=0, max_tokens=10)
        return "是" in resp.choices[0].message.content

    def run(self, task: str) -> dict:
        self.plan = self.plan_task(task)
        context = ""
        for step in self.plan:
            success = False
            for attempt in range(self.max_retries + 1):
                print(f"⚡ 执行步骤 {step['id']}: {step['description']} (尝试 {attempt+1})")
                result = self.execute_step(task, step, context)
                if self.check_step(step, result["result"]):
                    self.execution_log.append(result)
                    context += f"\n步骤{step['id']}完成: {result['result']}"
                    success = True
                    break
                else:
                    print(f"  ⚠️ 检查点失败，重新尝试...")
            if not success:
                return {"status": "failed", "failed_at": step["id"], "log": self.execution_log}
            time.sleep(0.3)
        return {"status": "success", "plan": self.plan, "execution_log": self.execution_log}

if __name__ == "__main__":
    agent = PlanExecuteAgent(max_retries=2)
    result = agent.run("编写一篇关于 Python 异步编程的 500 字技术文章")
    print(json.dumps(result, ensure_ascii=False, indent=2))

from openai import OpenAI
import base64, json, requests

client = OpenAI(api_key="your-key", base_url="https://api.deepseek.com/v1")

# 通义千问 VL 工具函数
def encode_image(image_path: str) -> str:
    """将本地图片编码为 base64"""
    with open(image_path, "rb") as f:
        return base64.b64encode(f.read()).decode("utf-8")

def analyze_image_deepseek(image_url: str, question: str = "请详细描述这张图片的内容") -> str:
    """使用 DeepSeek 多模态能力分析图片（需 DeepSeek VL 支持）"""
    # 注意: DeepSeek 当前主要通过 API 的 vision 能力支持图片
    # 这里使用 text-only 模式模拟多模态流程
    print(f"🖼️ 分析图片: {image_url[:50]}...")
    prompt = f"""[系统模拟多模态输入]
你正在分析一张图片。图片 URL: {image_url}
用户问题: {question}
请基于你对图片 URL 的推断和上下文，给出专业的图像分析回答。
（生产环境需替换为真正的 VL 模型 API 调用）"""
    resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], max_tokens=500)
    return resp.choices[0].message.content

class MultimodalAgent:
    """多模态智能体 - 支持图像+文本混合任务"""
    def __init__(self):
        self.tools = {
            "describe_image": self.describe_image,
            "extract_text": self.extract_text,
            "classify_image": self.classify_image,
            "generate_report": self.generate_report
        }
        self.tool_schemas = [
            {"name": "describe_image", "description": "生成图片的详细自然语言描述", "parameters": {"image_url": "string"}},
            {"name": "extract_text", "description": "从图片中提取文字（OCR）", "parameters": {"image_url": "string"}},
            {"name": "classify_image", "description": "对图片内容进行分类（图表/文档/照片/截图）", "parameters": {"image_url": "string"}},
            {"name": "generate_report", "description": "基于图片分析结果生成结构化报告", "parameters": {"analysis": "string"}}
        ]

    def describe_image(self, image_url: str) -> str:
        return analyze_image_deepseek(image_url, "详细描述这张图片的所有可见内容、布局和关键元素")

    def extract_text(self, image_url: str) -> str:
        return analyze_image_deepseek(image_url, "提取图片中所有的文字内容，保持原有格式")

    def classify_image(self, image_url: str) -> str:
        return analyze_image_deepseek(image_url, "这张图片属于什么类型？图表、文档、照片还是截图？")

    def generate_report(self, analysis: str) -> str:
        prompt = f"基于以下图片分析结果，生成一份结构化的报告（包含摘要、关键发现和建议）:\n{analysis}"
        resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], max_tokens=500)
        return resp.choices[0].message.content

    def decide_tools(self, query: str) -> list[str]:
        """根据用户意图决定调用哪些工具"""
        prompt = f"""用户请求: {query}
可用工具: {[t['name'] for t in self.tool_schemas]}
请判断需要调用哪些工具（可多选），用逗号分隔。只回答工具名。"""
        resp = client.chat.completions.create(model="deepseek-chat", messages=[{"role": "user", "content": prompt}], temperature=0, max_tokens=100)
        tools = [t.strip() for t in resp.choices[0].message.content.split(",")]
        return [t for t in tools if t in self.tools]

    def run(self, image_url: str, query: str) -> dict:
        print(f"📸 多模态任务: {query}")
        tools_to_use = self.decide_tools(query)
        print(f"🔧 调用工具: {tools_to_use}")
        results = {}
        for tool_name in tools_to_use:
            print(f"  ⚙️ 执行 {tool_name}...")
            if tool_name in ("describe_image", "extract_text", "classify_image"):
                results[tool_name] = self.tools[tool_name](image_url)
            elif tool_name == "generate_report":
                all_analysis = "\n".join(str(v) for v in results.values())
                results[tool_name] = self.tools[tool_name](all_analysis)
        return {"image": image_url[:50], "query": query, "tools_used": tools_to_use, "results": results}

if __name__ == "__main__":
    agent = MultimodalAgent()
    result = agent.run("https://example.com/chart.png", "分析这张图表并提取其中的数据和结论")
    print(json.dumps(result, ensure_ascii=False, indent=2))
